import React, { useEffect, useState } from 'react';
import axios from 'axios';

const MyOrders = () => {
  const [orders, setOrders] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const uid = localStorage.getItem("id", 0);

  useEffect(() => {
    fetchOrders();
  }, []);

  const fetchOrders = async () => {
    try {
      const response = await axios.get('http://localhost/Petshop/showorder.php?uid=' + uid);
      setOrders(response.data);
      setIsLoading(false);
    } catch (error) {
      console.error('Error fetching orders:', error);
    }
  };

  const navigateToHome = () => {
    window.location.href = '/'; // Redirect to the home page
  };

  return (
    <div style={{ fontFamily: 'Arial, sans-serif', padding: '20px' }}>
      <h2 style={{ textAlign: 'center', marginBottom: '20px' }}>My Orders</h2>
      <button style={{ backgroundColor: '#4CAF50', color: 'white', padding: '10px 20px', border: 'none', borderRadius: '4px', cursor: 'pointer', marginBottom: '20px' }} onClick={navigateToHome}>Go to Home</button>

      {isLoading ? (
        <p style={{ textAlign: 'center' }}>Loading...</p>
      ) : (
        <div style={{ maxWidth: '800px', margin: '0 auto' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse', backgroundColor: '#fff', borderRadius: '8px', boxShadow: '0 0 10px rgba(0, 0, 0, 0.1)' }}>
            <thead>
              <tr>
                <th style={{ padding: '10px', borderBottom: '1px solid #ddd', textAlign: 'left', backgroundColor: '#f2f2f2' }}>Order ID</th>
                <th style={{ padding: '10px', borderBottom: '1px solid #ddd', textAlign: 'left', backgroundColor: '#f2f2f2' }}>Total Items</th>
                <th style={{ padding: '10px', borderBottom: '1px solid #ddd', textAlign: 'left', backgroundColor: '#f2f2f2' }}>Order Date</th>
                <th style={{ padding: '10px', borderBottom: '1px solid #ddd', textAlign: 'left', backgroundColor: '#f2f2f2' }}>Total Amount</th>
              </tr>
            </thead>
            <tbody>
              {orders.map(order => (
                <tr key={order.oid}>
                  <td style={{ padding: '10px', borderBottom: '1px solid #ddd', textAlign: 'left' }}>{order.oid}</td>
                  <td style={{ padding: '10px', borderBottom: '1px solid #ddd', textAlign: 'left' }}>{order.totalitem}</td>
                  <td style={{ padding: '10px', borderBottom: '1px solid #ddd', textAlign: 'left' }}>{order.totalitem}</td>
                  <td style={{ padding: '10px', borderBottom: '1px solid #ddd', textAlign: 'left' }}>{order.amount}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default MyOrders;
